/* ============ STATE ============ */
const state={co:"meridian",scenario:"base",growth:22,rate:48};
const $=s=>document.querySelector(s), $$=s=>document.querySelectorAll(s);
const fmtMoney=n=>{const a=Math.abs(n);if(a>=1e6)return (n<0?'−':'')+'$'+(a/1e6).toFixed(1)+'M';if(a>=1e3)return (n<0?'−':'')+'$'+(a/1e3).toFixed(0)+'K';return (n<0?'−':'')+'$'+a.toFixed(0);};

/* ============ DIAL ============ */
function buildDial(score){
  const svg=$("#dial"),cx=100,cy=100,r=78,start=135,sweep=270;
  let h='';
  h+=`<defs>
    <linearGradient id="gSteel" x1="0" y1="0" x2="1" y2="1"><stop offset="0" stop-color="#3a3e46"/><stop offset="1" stop-color="#23262d"/></linearGradient>
    <linearGradient id="gGold" x1="0" y1="0" x2="1" y2="1"><stop offset="0" stop-color="#e7c25a"/><stop offset=".5" stop-color="#c9912f"/><stop offset="1" stop-color="#9a6c1c"/></linearGradient>
    <radialGradient id="gGlow"><stop offset="0" stop-color="rgba(201,145,47,.25)"/><stop offset="1" stop-color="transparent"/></radialGradient>
  </defs>`;
  h+=`<circle cx="100" cy="100" r="92" fill="url(#gGlow)"/>`;
  // ticks
  for(let i=0;i<=60;i++){const a=(start+sweep*(i/60))*Math.PI/180;const rr=(i%10===0)?70:74;const x1=cx+Math.cos(a)*rr,y1=cy+Math.sin(a)*rr,x2=cx+Math.cos(a)*78,y2=cy+Math.sin(a)*78;h+=`<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${i%10===0?'#4a4e56':'#2a2d34'}" stroke-width="${i%10===0?1.4:1}"/>`;}
  // track
  const polar=(ang)=>{const a=ang*Math.PI/180;return[cx+Math.cos(a)*r,cy+Math.sin(a)*r];};
  const arc=(a0,a1)=>{const[x0,y0]=polar(a0),[x1,y1]=polar(a1);const large=(a1-a0)>180?1:0;return`M${x0} ${y0} A${r} ${r} 0 ${large} 1 ${x1} ${y1}`;};
  h+=`<path d="${arc(start,start+sweep)}" stroke="#1c1e22" stroke-width="9" fill="none" stroke-linecap="round"/>`;
  const end=start+sweep*(score/100);
  h+=`<path id="dialArc" d="${arc(start,end)}" stroke="url(#gGold)" stroke-width="9" fill="none" stroke-linecap="round" filter="drop-shadow(0 0 6px rgba(201,145,47,.5))"/>`;
  // needle marker
  const[nx,ny]=polar(end);
  h+=`<circle cx="${nx}" cy="${ny}" r="6" fill="#fff0bf" stroke="#9a6c1c" stroke-width="1.5"/>`;
  svg.innerHTML=h;
  // animate arc
  const path=$("#dialArc");const len=path.getTotalLength();
  path.style.strokeDasharray=len;path.style.strokeDashoffset=len;
  requestAnimationFrame(()=>{path.style.transition="stroke-dashoffset 1.4s cubic-bezier(.2,.8,.2,1)";path.style.strokeDashoffset=0;});
  // count up
  const el=$("#scoreNum");let cur=0;const tgt=score;const t0=performance.now();
  function step(t){const p=Math.min(1,(t-t0)/1300);el.textContent=Math.round(tgt*(1-Math.pow(1-p,3)));if(p<1)requestAnimationFrame(step);}
  requestAnimationFrame(step);
}

/* ============ SPARKLINE ============ */
function spark(data,w=120,h=30,color="#5b86a6"){
  const min=Math.min(...data),max=Math.max(...data),rng=(max-min)||1;
  const pts=data.map((v,i)=>[6+i*(w-12)/(data.length-1),h-3-((v-min)/rng)*(h-8)]);
  const d=pts.map((p,i)=>(i?'L':'M')+p[0].toFixed(1)+' '+p[1].toFixed(1)).join(' ');
  const area=d+`L${pts[pts.length-1][0].toFixed(1)} ${h} L${pts[0][0].toFixed(1)} ${h} Z`;
  const id='sp'+Math.random().toString(36).slice(2,7);
  return`<svg class="spark" viewBox="0 0 ${w} ${h}" preserveAspectRatio="none" style="width:100%"><defs><linearGradient id="${id}" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="${color}" stop-opacity=".22"/><stop offset="1" stop-color="${color}" stop-opacity="0"/></linearGradient></defs><path d="${area}" fill="url(#${id})"/><path d="${d}" fill="none" stroke="${color}" stroke-width="1.6"/></svg>`;
}

