function renderCommand(){
  const c=COMPANIES[state.co];
  buildDial(c.score);
  $("#scoreLabel").textContent=c.grade;
  $("#verdictTxt").innerHTML=c.verdict;
  $("#verdictMeta").innerHTML=`
    <div>Runway<b>${c.runway}${c.runway.length<4?' mo':''}</b></div>
    <div>Cash position<b>${c.cash}</b></div>
    <div>Monthly burn<b>${c.burn}</b></div>`;
  // vitals
  $("#vitals").innerHTML=c.vitals.map(v=>{
    const col=v.cls==='pos'?'var(--pos)':v.cls==='neg'?'var(--neg)':'var(--neutral)';
    const arrow=v.cls==='pos'?'▲':v.cls==='neg'?'▼':'•';
    return`<div class="panel vital">
      <div class="vl"><span class="name">${v.name}</span>
        <span class="trace" data-trace="${v.name}"><svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M9 12l2 2 4-4"/></svg>trace</span></div>
      <div class="big">${v.val}</div>
      <div class="delta" style="color:${col}">${arrow} ${v.d}</div>
      ${spark(v.spark,120,30,col)}
    </div>`;}).join('');
  // action queue
  const acts=ACTIONS[state.co];
  $("#aqMeta").textContent=acts.length+" actions · everything else handled";
  $("#actionQueue").innerHTML=acts.map((a,i)=>`
    <div class="aq-item" data-aq="${i}">
      <div class="aq-sev ${a.sev}"></div>
      <div class="aq-body">
        <div class="aq-tag">${a.tag}</div>
        <div class="aq-title">${a.title}</div>
        <div class="aq-desc">${a.desc}</div>
        <div class="aq-impact">${a.impact}</div>
        <div class="aq-actions"><button class="btn gold" data-approve="${i}">${a.act}</button><button class="btn" data-dismiss="${i}">Later</button></div>
      </div>
    </div>`).join('');
  bindTrace();
  $$("[data-approve]").forEach(b=>b.onclick=()=>onApprove(+b.dataset.approve,acts,b));
  $$("[data-dismiss]").forEach(b=>b.onclick=()=>{const i=+b.dataset.dismiss;const item=$(`[data-aq="${i}"]`);item.style.opacity=.4;b.textContent="Snoozed";b.disabled=true;});
}

