/* ============ CASH ============ */
function renderCash(){
  const c=COMPANIES[state.co];
  $("#cashStats").innerHTML=`
    ${cashStat("Cash today",c.cash,"reconciled to the cent","var(--silver-bright)")}
    ${cashStat("Lowest point (13wk)",fmtMoney(parseFloat(c.cash.replace(/[$MK]/g,''))*(c.cash.includes('M')?1e6:1e3)*0.78),"week 9 · still safe","var(--warn)")}
    ${cashStat("Net 13-week change",c.co==='harbor'?"−$0.4M":"+$1.2M","after planned moves",c.co==='harbor'?"var(--neg)":"var(--pos)")}
    ${cashStat("Days payable / receivable",c.co==='harbor'?"42 / 58":"38 / 44","optimizing","var(--neutral)")}`;
  // 13 week bars
  const weeks=13;const data=[];let seed=c.co==='harbor'?-1:1;
  for(let i=0;i<weeks;i++){data.push((Math.sin(i*1.3)+ (Math.random()*0.6-0.3))*220*seed + (c.co==='olive'?40:c.co==='harbor'?-60:120));}
  drawCashChart(data);
  $("#cashActions").innerHTML=[
    {t:"Scheduled $182K receivable for Friday",d:"Auto-reminder sent, payment confirmed"},
    {t:"Delayed two non-critical payables 6 days",d:"Smooths the week-9 dip, no late fees"},
    {t:"Swept $4M into 4-week T-bills",d:"Keeps you liquid, earns 5.1%"},
    {t:"Pre-staged payroll funding",d:"Cleared 2 days ahead, every run"}
  ].map(a=>`<div style="padding:13px 16px;border-bottom:1px solid var(--line)"><div style="display:flex;gap:9px;align-items:flex-start"><span style="color:var(--pos);margin-top:2px">✓</span><div><div style="font-size:12.5px;color:var(--silver-bright)">${a.t}</div><div style="font-size:11px;color:var(--faint);margin-top:2px">${a.d}</div></div></div></div>`).join('');
}
function cashStat(l,v,d,col){return`<div class="s"><div class="sl">${l}</div><div class="sv">${v}</div><div class="sd" style="color:${col}">${d}</div></div>`;}
function drawCashChart(data){
  const svg=$("#cashChart"),W=860,H=300,pl=46,pr=18,pt=20,pb=30;
  const max=Math.max(...data.map(Math.abs))*1.2;const zy=pt+(H-pt-pb)/2;
  const bw=(W-pl-pr)/data.length*0.62;
  let h='';
  h+=`<line x1="${pl}" y1="${zy}" x2="${W-pr}" y2="${zy}" stroke="#2a2d34" stroke-width="1"/>`;
  data.forEach((v,i)=>{
    const x=pl+i*(W-pl-pr)/data.length+(W-pl-pr)/data.length*0.19;
    const bh=Math.abs(v)/max*((H-pt-pb)/2);
    const y=v>=0?zy-bh:zy;const pos=v>=0;const cur=i===0;
    const fill=cur?'url(#cb)':pos?'#3a4754':'#4a3530';
    h+=`<rect x="${x}" y="${y}" width="${bw}" height="${bh}" rx="1.5" fill="${cur?'#c9912f':pos?'#476079':'#7a4a3c'}" opacity="${cur?1:.85}"/>`;
    if(i%2===0)h+=`<text x="${x+bw/2}" y="${H-10}" fill="#565b64" font-size="9" font-family="JetBrains Mono" text-anchor="middle">W${i+1}</text>`;
  });
  h+=`<text x="${pl+(W-pl-pr)/data.length*0.5}" y="${pt+10}" fill="#e7c25a" font-size="9" font-family="Saira" letter-spacing="1">THIS WEEK</text>`;
  svg.innerHTML=h;
}

