/* ============ INGEST PIPELINE ============ */
const PL_STAGES=["Parse","Classify","Extract","Reconcile","Post","Insight"];
function runPipeline(filename,onDone){
  const pl=$("#pipeline");pl.classList.add('show');
  $("#plFile").innerHTML=`<span style="color:var(--gold-bright)">▣</span> ${filename}`;
  $("#plStages").innerHTML=PL_STAGES.map((s,i)=>`<div class="pl-stage" id="pls${i}"><div class="dot">${i+1}</div><div class="nm">${s}</div></div>`).join('');
  let i=0;
  const iv=setInterval(()=>{
    if(i>0)$("#pls"+(i-1)).className="pl-stage done",$("#pls"+(i-1)+" .dot").innerHTML="✓";
    if(i<PL_STAGES.length){$("#pls"+i).className="pl-stage active";i++;}
    else{clearInterval(iv);
      if(onDone){ onDone(); setTimeout(()=>pl.classList.remove('show'),2200); }
      else{
        $("#fsTxn").textContent=(+$("#fsTxn").textContent.replace(/,/g,'')+ Math.floor(Math.random()*40+18)).toLocaleString();
        const amt=Math.floor(Math.random()*9000+1500);
        addOp('doc',`Read <b>${filename}</b> — extracted 1 invoice, matched it to a PO, and posted it. Flagged a <span class="amt">${fmtMoney(amt)}</span> overcharge.`,'Ingest');
        bumpSaved(amt);
        toast(`<b>${filename}</b> processed. Found a ${fmtMoney(amt)} discrepancy.`);
        setTimeout(()=>pl.classList.remove('show'),2600);
      }
    }
  },680);
}

