$("#cmdInput").onkeydown=e=>{if(e.key==='Enter'){const sel=$("#cmdList .cmd-item[data-v]");const q=e.target.value;if(sel)cmdPick(sel.dataset.v,q);else{$("#cmdOverlay").classList.remove('show');openAsk(q);}}};
