const TRACE_D="M58 52 L180 277 L326 31";
const EMBLEM=`<span class="logo-emblem"><img class="le-img" src="data:image/png;base64," alt="Valtier"><svg class="le-trace" viewBox="0 0 360 294" preserveAspectRatio="xMidYMid meet" aria-hidden="true"><path class="vrail" d="${TRACE_D}" fill="none" stroke-width="3" stroke-linecap="round" pathLength="120"/><path class="vspark" d="${TRACE_D}" fill="none" stroke-width="3.6" stroke-linecap="round" pathLength="120"/><path class="vspark2" d="${TRACE_D}" fill="none" stroke-width="2" stroke-linecap="round" pathLength="120"/></svg></span>`;
