/* ---- Persistent memory (graceful if storage blocked) ---- */
const MEM={
  K:"valtier.v2",
  _read(){try{return JSON.parse(localStorage.getItem(this.K))||{};}catch(e){return {};}},
  _write(o){try{localStorage.setItem(this.K,JSON.stringify(o));}catch(e){}},
  session(){return this._read().session||null;},
  setSession(s){const o=this._read();o.session=s;this._write(o);},
  clearSession(){const o=this._read();delete o.session;this._write(o);},
  _key(){const s=this.session();return "co_"+((s&&(s.company||s.email))||"demo").toLowerCase().replace(/[^a-z0-9]/g,"");},
  company(){const o=this._read();return (o.cos&&o.cos[this._key()])||{savings:0,fixed:[],firstRun:true,since:null};},
  saveCompany(c){const o=this._read();o.cos=o.cos||{};o.cos[this._key()]=c;this._write(o);},
  addSaving(amt,label){const c=this.company();c.savings=(c.savings||0)+amt;(c.fixed=c.fixed||[]).push({amt,label,t:Date.now()});this.saveCompany(c);return c.savings;}
};

/* ---- App state ---- */
let appStarted=false, authMode="signup";
/* ===== LIVE BACKEND ================================================
   Standalone demo  : VALTIER_LIVE = false  (accounts + memory in this browser)
   One-roof deploy   : VALTIER_LIVE = true,  VALTIER_API = ""   (served by the backend)
   Split hosting     : VALTIER_LIVE = true,  VALTIER_API = "https://your-api-url"
   See RUNBOOK.md. */
const VALTIER_LIVE=true;
const VALTIER_API="";
let pendingUserId=null;
function liveMode(){return VALTIER_LIVE===true;}
async function api(path,opts){
  opts=opts||{};
  const tok=(MEM.session()&&MEM.session().token)||"";
  const res=await fetch((VALTIER_API||"")+"/api"+path,{method:opts.method||"GET",
    headers:Object.assign({"Content-Type":"application/json"},tok?{"Authorization":"Bearer "+tok}:{},opts.headers||{}),
    body:opts.body?JSON.stringify(opts.body):undefined});
  let data={};try{data=await res.json();}catch(e){}
  if(!res.ok)throw new Error(data.error||("Request failed ("+res.status+")"));
  return data;
}
function isDemo(){const s=MEM.session();return !s||s.plan==="demo";}
function curName(){const s=MEM.session();return (s&&s.name)?s.name.split(" ")[0]:"there";}

/* ---- AUTH ---- */
const PERSONAL_DOMAINS=["gmail.com","yahoo.com","outlook.com","hotmail.com","icloud.com","aol.com","proton.me","protonmail.com","gmx.com","mail.com","live.com","msn.com","yandex.com"];
function validEmail(v){return /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(v);}
function isWorkEmail(v){if(!validEmail(v))return false;const d=v.split("@")[1].toLowerCase();return !PERSONAL_DOMAINS.includes(d);}
function companyFromEmail(v){try{const d=v.split("@")[1].split(".")[0];return d.charAt(0).toUpperCase()+d.slice(1);}catch(e){return "Your Company";}}

function setAuthMode(m){
  authMode=m;
  $$(".ac-tab").forEach(t=>t.classList.toggle("active",t.dataset.mode===m));
  document.querySelectorAll(".signup-only").forEach(el=>el.style.display=m==="signup"?"":"none");
  $("#acTitle").textContent=m==="signup"?"Create your account":"Welcome back";
  $("#acSub").textContent=m==="signup"?"Start with a full live demo — no card required.":"Sign in to your finance command center.";
  $("#acContinue").textContent=m==="signup"?"Continue securely":"Sign in securely";
}
function pwScore(v){let s=0;if(v.length>=8)s++;if(v.length>=12)s++;if(/[a-z]/.test(v)&&/[A-Z]/.test(v))s++;if(/\d/.test(v))s++;if(/[^A-Za-z0-9]/.test(v))s++;return Math.min(s,4);}

function gateContinue(){ gateContinueAsync(); }
async function gateContinueAsync(){
  const email=$("#inEmail").value.trim();
  const pw=$("#inPw").value;
  let ok=true;
  if(!isWorkEmail(email)){$("#inEmail").classList.add("bad");$("#emailHint").classList.add("err");$("#emailHint").textContent=validEmail(email)?"Please use your company email — personal domains aren\u2019t accepted.":"Enter a valid email address.";ok=false;}
  else {$("#inEmail").classList.remove("bad");$("#emailHint").classList.remove("err");$("#emailHint").textContent="Looks good — that\u2019s a company domain.";}
  if(pw.length<(authMode==="signup"?12:6)){$("#inPw").classList.add("bad");ok=false;} else $("#inPw").classList.remove("bad");
  if(authMode==="signup"&&!$("#inName").value.trim()){$("#inName").classList.add("bad");ok=false;} else $("#inName").classList.remove("bad");
  if(!ok)return;
  if(liveMode()){
    try{
      if(authMode==="signup"){const r=await api("/auth/register",{method:"POST",body:{name:$("#inName").value.trim(),email,company:$("#inCo").value.trim(),password:pw}});pendingUserId=r.userId;}
      else{const r=await api("/auth/login",{method:"POST",body:{email,password:pw}});pendingUserId=r.userId;}
    }catch(e){$("#inPw").classList.add("bad");$("#emailHint").classList.add("err");$("#emailHint").textContent=e.message;return;}
  }
  $("#mfaTo").textContent=email;
  $("#acStep1").style.display="none";$("#acStep2").style.display="";
  setTimeout(()=>{const f=$("#mfaCode").children[0];if(f)f.focus();},60);
}
function doSSO(provider){
  const email=$("#inEmail").value.trim()|| ("you@"+(($("#inCo").value.trim()||"company").toLowerCase().replace(/[^a-z0-9]/g,""))+".com");
  $("#inEmail").value=email;$("#mfaTo").textContent=email;
  toast(`<b>${provider}</b> — federated sign-in verified. One more step.`);
  $("#acStep1").style.display="none";$("#acStep2").style.display="";
  setTimeout(()=>{const f=$("#mfaCode").children[0];if(f)f.focus();},60);
}
function mfaVerify(){ mfaVerifyAsync(); }
async function mfaVerifyAsync(){
  const email=$("#inEmail").value.trim();
  const name=$("#inName").value.trim()|| (MEM.session()&&MEM.session().name) || "Operator";
  const company=$("#inCo").value.trim()||companyFromEmail(email);
  if(liveMode()){
    const code=Array.from($("#mfaCode").children).map(i=>i.value).join("")||"739204";
    try{
      const r=await api("/auth/mfa",{method:"POST",body:{userId:pendingUserId,code}});
      const sess={name:(r.user&&r.user.name)||name,email,company:(r.user&&r.user.company)||company,token:r.accessToken,refresh:r.refreshToken,plan:null};
      MEM.setSession(sess);
      try{const sub=await api("/subscription");sess.plan=(sub&&sub.plan)||"demo";}catch(e){sess.plan="demo";}
      MEM.setSession(sess);
      hideGate();
      if(sess.plan&&sess.plan!=="demo")enterApp(); else showPricing();
    }catch(e){toast(e.message||"Verification failed.");}
    return;
  }
  const prior=MEM._read().cos&&MEM._read().cos["co_"+(company||email).toLowerCase().replace(/[^a-z0-9]/g,"")];
  MEM.setSession({name,email,company,plan:(MEM.session()&&MEM.session().plan)||null});
  if(authMode==="signin"&&prior&&prior.plan){MEM.setSession({name,email,company,plan:prior.plan});hideGate();enterApp();return;}
  hideGate();showPricing();
}

