/* ---- REMEDIATION: Valtier executes the fix ---- */
function parseAmt(str){const m=String(str).match(/\$([\d.,]+)\s*([MK])?/);if(!m)return 0;let n=parseFloat(m[1].replace(/,/g,""));if(m[2]==="M")n*=1e6;else if(m[2]==="K")n*=1e3;return Math.round(n);}
function onApprove(i,acts,b){
  const a=acts[i];const item=$(`[data-aq="${i}"]`);
  if(!item||item.dataset.resolved)return;
  if(isDemo()){openPaywall();return;}
  runRemediation(i,a,item);
}
function runRemediation(i,a,item,amtOverride){
  if(!item||item.dataset.resolved)return;
  item.dataset.resolved="1";
  const actions=item.querySelector(".aq-actions");if(actions)actions.style.display="none";
  const steps=["Validating the finding against source records","Preparing the action — "+a.act.toLowerCase(),"Executing autonomously","Posting to the ledger & writing to memory"];
  const box=document.createElement("div");box.className="fix-steps show";
  box.innerHTML=steps.map(s=>`<div class="fix-step"><span class="fs-ic"><svg viewBox="0 0 24 24"><path d="M5 12l4 4 9-10"/></svg></span><span>${s}</span></div>`).join("");
  item.querySelector(".aq-body").appendChild(box);
  const rows=box.querySelectorAll(".fix-step");let k=0;
  function tick(){
    if(k>0)rows[k-1].classList.remove("active"),rows[k-1].classList.add("done");
    if(k<rows.length){rows[k].classList.add("active");k++;setTimeout(tick,760);}
    else finish();
  }
  function finish(){
    const amt=(amtOverride!=null)?amtOverride:parseAmt(a.impact);
    const res=document.createElement("div");res.className="fix-result";
    res.innerHTML=`<svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="var(--pos)" stroke-width="2"><path d="M5 12l4 4 9-10"/></svg><span>Done. ${a.impact}.${amt?` <b>${fmtMoney(amt)}</b> banked.`:""}</span>`;
    box.appendChild(res);
    const tag=item.querySelector(".aq-tag");if(tag)tag.insertAdjacentHTML("beforeend",' <span class="aq-badge">Resolved by Valtier</span>');
    item.classList.add("aq-resolved");
    if(amt){const total=MEM.addSaving(amt,a.title.split(",")[0]);bumpSaved(amt);updateChips();}
    addOp("done",`<b>Resolved:</b> ${a.title.split(",")[0]} — executed end-to-end and logged.`,"Action");
    toast(`<b>${a.act}</b> — done. I handled it.${amt?` ${fmtMoney(amt)} recovered.`:""}`);
    const remaining=$$(".aq-item:not(.aq-resolved)").length;
    $("#aqMeta").textContent=remaining+" actions · everything else handled";
  }
  tick();
}

