let tutN=0;
function showTutorial(){tutN=0;$("#tutWelcome").style.display="";$("#tutor").classList.remove("steps");$("#tutor").classList.add("show");}
function startTutSteps(){$("#tutWelcome").style.display="none";$("#tutor").classList.add("steps");$("#tutDots").innerHTML=TUT.map((_,i)=>`<i></i>`).join("");renderTut();}
function renderTut(){
  const step=TUT[tutN];if(!step)return finishTut();
  if(step.pre)step.pre();
  const el=document.querySelector(step.sel);
  if(!el){tutN++;return renderTut();}
  el.scrollIntoView({block:"center",behavior:"smooth"});
  setTimeout(()=>{
    const r=el.getBoundingClientRect();
    const ring=$("#tutRing");
    ring.style.left=(r.left-7)+"px";ring.style.top=(r.top-7)+"px";ring.style.width=(r.width+14)+"px";ring.style.height=(r.height+14)+"px";
    const pop=$("#tutPop");const pw=316,ph=pop.offsetHeight||190;
    let left,top;
    if(r.right<160){left=r.right+20;top=Math.max(16,Math.min(r.top,window.innerHeight-ph-16));}
    else if(r.bottom+ph+20<window.innerHeight){left=Math.min(Math.max(16,r.left),window.innerWidth-pw-16);top=r.bottom+18;}
    else {left=Math.min(Math.max(16,r.left),window.innerWidth-pw-16);top=Math.max(16,r.top-ph-18);}
    pop.style.left=left+"px";pop.style.top=top+"px";
    $("#tpTitle").innerHTML=step.title;$("#tpBody").innerHTML=step.body;
    $("#tpStepLbl").textContent=`STEP ${tutN+1} / ${TUT.length}`;
    $$("#tutDots i").forEach((d,i)=>d.classList.toggle("on",i===tutN));
    $("#tutNext").textContent=tutN===TUT.length-1?"Finish":"Next";
    if(step.demo){setTimeout(()=>{const first=$("#actionQueue .aq-item:not(.aq-resolved)");if(first){const idx=+first.dataset.aq;runRemediation(idx,ACTIONS[state.co][idx],first);}},700);}
  },320);
}
function nextTut(){tutN++;if(tutN>=TUT.length)finishTut();else renderTut();}
function finishTut(){
  $("#tutor").classList.remove("show");
  const c=MEM.company();c.firstRun=false;if(!c.since)c.since=Date.now();MEM.saveCompany(c);
  toast(`You\u2019re set, ${curName()}. My memory is active — I\u2019ll remember everything from here.`);
}

